<template>
  <div class="echart" id="map" ref="map"></div>
</template>
<script setup>
import { cityData, cityLngLat } from "@/tempData/tempData.ts";
import { ref, reactive, onMounted } from "vue";
import * as echarts from "echarts";
import "@/assets/map/js/china.js"; // 核心文件
let chinaDatas = reactive([]);
const map = ref(null);

let chinaGeoCoordMap = reactive({
  阿勒泰: [94.69705, 43.25543]
});
let myChart = reactive(null);
console.log(echarts);
const convertData = (data) => {
  var res = [];
  for (var i = 0; i < data.length; i++) {
    var dataItem = data[i];
    var fromCoord = [94.69705, 43.25543];
    var toCoord = chinaGeoCoordMap[dataItem[0].name];
    if (fromCoord && toCoord) {
      res.push([
        {
          coord: fromCoord,
          value: `阿勒泰->${dataItem[0].name}<br/>${dataItem[0].value}吨`
        },
        {
          coord: toCoord
        }
      ]);
    }
  }
  return res;
};

onMounted(() => {
  drawEcharts();
});
const drawEcharts = () => {
  var series = [];
  [["阿勒泰", chinaDatas]].forEach(function (item) {
    series.push(
      {
        name: "阿勒泰",
        type: "lines",
        zlevel: 2,
        effect: {
          //飞线箭头
          show: true,
          period: 4, //箭头指向速度，值越小速度越快
          trailLength: 0.02, //特效尾迹长度[0,1]值越大，尾迹越长重
          symbol: "arrow", //箭头图标
          symbolSize: 8 //图标大小
        },
        lineStyle: {
          normal: {
            width: 1, //尾迹线条宽度
            opacity: 1, //尾迹线条透明度
            curveness: 0.3, //尾迹线条曲直度
            color: "#02E3AB"
          }
        },
        data: convertData(item[1])
      },
      {
        //气泡点
        type: "effectScatter",
        tooltip: {
          show: false
        },
        coordinateSystem: "geo",
        zlevel: 2,
        rippleEffect: {
          //涟漪特效
          number: 1,
          period: 4, //动画时间，值越小速度越快
          brushType: "fill", //波纹绘制方式 stroke, fill
          scale: 1 //波纹圆环最大限制，值越大波纹越大
        },
        label: {
          normal: {
            show: true,
            position: "bottom", //显示位置
            offset: [0, 0], //偏移设置
            formatter: function (params) {
              //圆环显示文字
              return params.data.name;
            },
            fontSize: 13,
            color: "#fff"
          },
          emphasis: {
            show: true
          }
        },
        symbol: "circle",
        itemStyle: {
          normal: {
            show: true,
            color: {
              type: "radial", // 径向渐变
              x: 0.5, // 圆心坐标（中心）
              y: 0.5,
              r: 1, // 半径长度
              colorStops: [
                {
                  offset: 0,
                  color: "#87EAFF" // offset：坐标为0处的颜色
                },
                {
                  offset: 0.5,
                  color: "#04AFFF" // offset：坐标为1处的颜色
                }
              ]
            }
          }
        },
        data: item[1].map(function (dataItem) {
          return {
            name: dataItem[0].name,
            value: chinaGeoCoordMap[dataItem[0].name].concat([dataItem[0].value | 0])
          };
        })
      },
      {
        //阿勒泰
        type: "scatter",
        coordinateSystem: "geo",
        zlevel: 2,
        rippleEffect: {
          period: 4,
          brushType: "stroke",
          scale: 4
        },
        label: {
          normal: {
            show: true,
            position: "top",
            color: "#0A6A65",
            formatter: "{b}",
            fontSize: 18,
            backgroundColor: "#FFE425",
            borderRadius: 6,
            padding: 5,
            textStyle: {
              color: "#0A6A65"
            }
          },
          emphasis: {
            show: false,
            color: "#f60"
          }
        },
        itemStyle: {
          color: "#FFE425"
        },
        symbol:
          "image://data:image/png;base64,",
        symbolSize: 25,
        data: [
          {
            name: item[0],
            value: chinaGeoCoordMap[item[0]].concat([10])
          }
        ]
      }
    );
  });
  let option = {
    tooltip: {
      formatter: function (params) {
        return params.data.value;
      },
      textStyle: {
        align: "center"
      }
    },
    geo: {
      map: "china",
      zoom: 1.2,
      label: {
        emphasis: {
          show: true, //鼠标划过高亮显示地方名
          color: "#fff"
        }
      },
      roam: false, //是否允许缩放
      itemStyle: {
        normal: {
          color: "#02ACA6",
          borderColor: "#013C52", //省市边界线00fcff 516a89
          borderWidth: 2
        },
        emphasis: {
          color: "#00FFC0" //悬浮背景
        }
      }
    },
    series: series
  };
  myChart = echarts.init(document.getElementById("map"));
  myChart.setOption(option);
};

const getLatLng = () => {
  let keys = Object.keys(cityLngLat);
  keys.forEach((v) => {
    chinaGeoCoordMap[cityLngLat[v].name] = [cityLngLat[v].longitude, cityLngLat[v].latitude];
  });
};

const flowInfo = () => {
  let toAddress = [];
  cityData.forEach((v) => {
    toAddress.push([
      {
        name: v.toAddress,
        value: v.tonnage //吨数
      }
    ]);
  });
  chinaDatas = toAddress;
  getLatLng();
};
flowInfo();
</script>
<style scoped>
.echart {
  /* width: 87.5rem; */
  /* height: 61.375rem; */
  width: 100%;
  height: 100%;
}
</style>
